import { RPCHandler } from "@orpc/server/fetch";

// Minimal handler to understand oRPC request format
const { implement } = await import("@orpc/server");
const { oc } = await import("@orpc/contract");
const { z } = await import("zod");

const contract = { echo: oc.input(z.object({ msg: z.string() })).output(z.object({ msg: z.string() })) };
const os = implement(contract).$context();
const echo = os.echo.handler(({ input }) => ({ msg: input.msg }));
const router = os.router({ echo });
const h = new RPCHandler(router);

// Try different body formats
const tests = [
  // plain JSON
  new Request("http://localhost/rpc/echo", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ msg: "hi" }) }),
  // nested input
  new Request("http://localhost/rpc/echo", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ input: { msg: "hi" } }) }),
];

for (const req of tests) {
  const { matched, response } = await h.handle(req, { prefix: "/rpc", context: {} });
  const body = await response.text();
  console.log(response.status, body);
}
' 2>&1

