 1→import { ORPCError } from "@orpc/server";
 2→import { member, organization } from "@rudel/sql-schema";
 3→import { eq } from "drizzle-orm";
 4→import { getClickhouse } from "./clickhouse.js";
 5→import { db } from "./db.js";
 6→import { analyticsRouter } from "./handlers/analytics/index.js";
 7→import { ingestSession } from "./ingest.js";
 8→import { authMiddleware, os } from "./middleware.js";
 9→
10→const health = os.health.handler(() => {
11→	return {
12→		status: "ok" as const,
13→		timestamp: Date.now(),
14→	};
15→});
16→
17→const me = os.me.use(authMiddleware).handler(({ context }) => {
18→	return {
19→		id: context.user.id,
20→		email: context.user.email,
21→		name: context.user.name,
22→		image: context.user.image ?? null,
23→		activeOrganizationId:
24→			((context.session as Record<string, unknown>).activeOrganizationId as
25→				| string
26→				| null) ?? null,
27→	};
28→});
29→
30→const listMyOrganizations = os.listMyOrganizations
31→	.use(authMiddleware)
32→	.handler(async ({ context }) => {
33→		const memberships = await db
34→			.select({
35→				id: organization.id,
36→				name: organization.name,
37→				slug: organization.slug,
38→				logo: organization.logo,
39→			})
40→			.from(member)
41→			.innerJoin(organization, eq(member.organizationId, organization.id))
42→			.where(eq(member.userId, context.user.id));
43→
44→		return memberships.map((m) => ({
45→			id: m.id,
46→			name: m.name,
47→			slug: m.slug,
48→			logo: m.logo ?? null,
49→		}));
50→	});
51→
52→const ingestSessionHandler = os.ingestSession
53→	.use(authMiddleware)
54→	.handler(async ({ input, context }) => {
55→		const orgId =
56→			input.organizationId ??
57→			((context.session as Record<string, unknown>).activeOrganizationId as
58→				| string
59→				| null) ??
60→			context.user.id;
61→
62→		if (input.organizationId) {
63→			const membership = await db
64→				.select({ id: member.id })
65→				.from(member)
66→				.where(eq(member.organizationId, input.organizationId))
67→				.limit(1);
68→
69→			if (membership.length === 0) {
70→				throw new ORPCError("FORBIDDEN", {
71→					message: "Not a member of the specified organization",
72→				});
73→			}
74→		}
75→
76→		await ingestSession(getClickhouse(), input, {
77→			userId: context.user.id,
78→			organizationId: orgId,
79→		});
80→
81→		return {
82→			success: true as const,
83→			sessionId: input.sessionId,
84→		};
85→	});
86→
87→export const router = os.router({
88→	health,
89→	me,
90→	listMyOrganizations,
91→	ingestSession: ingestSessionHandler,
92→	analytics: analyticsRouter,
93→});
94→

# StandardRPCCodec Source Code

Based on the GitHub page content, here's the complete source code of `rpc-codec.ts`:

```typescript
import type { ORPCError } from '@orpc/client'
import type { StandardRPCSerializer } from '@orpc/client/standard'
import type { StandardBody, StandardLazyRequest, StandardResponse } from '@orpc/standard-server'
import type { AnyProcedure } from '../../procedure'
import type { StandardCodec, StandardParams } from './types'
import { parseEmptyableJSON } from '@orpc/shared'

export class StandardRPCCodec implements StandardCodec {
  constructor(
    private readonly serializer: StandardRPCSerializer,
  ) {}

  async decode(request: StandardLazyRequest, _params: StandardParams | undefined, _procedure: AnyProcedure): Promise<unknown> {
    const serialized = request.method === 'GET'
      ? parseEmptyableJSON(request.url.searchParams.getAll('data').at(-1)) // this prevent duplicate data params
      : await request.body()

    return this.serializer.deserialize(serialized)
  }

  encode(output: unknown, _procedure: AnyProcedure): StandardResponse {
    return {
      status: 200,
      headers: {},
      body: this.serializer.serialize(output) as StandardBody,
    }
  }

  encodeError(error: ORPCError<any, any>): StandardResponse {
    return {
      status: error.status,
      headers: {},
      body: this.serializer.serialize(error.toJSON()) as StandardBody,
    }
  }
}
```

The `decode` method conditionally processes request data: for GET requests it parses URL search parameters, otherwise it awaits the request body, then passes the result to "the serializer's deserialize method."

